import { Container, Statistic, Badge, Separator } from "@gunjo/ui";
import { ManageClient } from "./ManageClient";
import { CareLevelDistribution } from "./CareLevelDistribution";
import {
  visits,
  clients,
  helpers,
  todayLabel,
  officeName,
  supervisorName,
  careLevelLabel,
  type CareLevel,
} from "./data";

export const metadata = {
  title: "訪問介護 サービス提供管理 | あおぞら訪問介護ステーション",
  description: "サービス提供責任者向けの本日の訪問スケジュール・利用者・実績管理画面",
};

export default function HomeCarePage() {
  // ── 本日のサマリ集計 ──
  const total = visits.length;
  const done = visits.filter((v) => v.status === "完了").length;
  const inProgress = visits.filter((v) => v.status === "実施中").length;
  const notDone = visits.filter((v) => v.status === "未実施").length;
  const activeHelpers = helpers.filter((h) => h.duty === "稼働中").length;
  const conflicts = visits.filter((v) => v.conflict).length;

  // ── 要介護度の分布 ──
  const dist = ([1, 2, 3, 4, 5] as CareLevel[]).map((lvl) => ({
    label: careLevelLabel(lvl),
    value: clients.filter((c) => c.careLevel === lvl).length,
  }));

  return (
    <Container size="2xl" className="py-6 sm:py-8">
      {/* ───────────── ヘッダー ───────────── */}
      <header className="mb-6 space-y-1.5">
        <div className="flex flex-wrap items-center gap-2 text-sm text-muted-foreground">
          <span>{officeName}</span>
          <span aria-hidden>·</span>
          <span className="tabular-nums">{todayLabel}</span>
        </div>
        <h1 className="text-2xl font-bold tracking-tight sm:text-3xl">
          訪問介護 サービス提供管理
        </h1>
        <p className="text-sm text-muted-foreground">{supervisorName}</p>
      </header>

      {/* ───────────── 本日のサマリ指標 ───────────── */}
      <section aria-label="本日のサマリ" className="mb-6">
        <div className="grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-6">
          <Statistic label="本日の訪問予定" value={total} hint="件" />
          <Statistic
            label="完了"
            value={done}
            change={`${Math.round((done / total) * 100)}%`}
            trend="up"
            tone="positive"
            hint="進捗"
          />
          <Statistic label="実施中" value={inProgress} hint="件" />
          <Statistic
            label="未実施"
            value={notDone}
            change={notDone > 0 ? "要確認" : "なし"}
            trend={notDone > 0 ? "down" : "flat"}
            tone={notDone > 0 ? "negative" : "neutral"}
          />
          <Statistic label="担当利用者数" value={clients.length} hint="名" />
          <Statistic label="稼働ヘルパー" value={`${activeHelpers}/${helpers.length}`} hint="名" />
        </div>
      </section>

      {/* ───────────── 要介護度の分布 ───────────── */}
      <section aria-label="要介護度の分布" className="mb-6 space-y-2">
        <div className="flex flex-wrap items-center gap-2">
          <h2 className="text-sm font-semibold text-foreground">担当利用者の要介護度分布</h2>
          {conflicts > 0 && (
            <Badge variant="destructive">本日 時間競合 {conflicts}件</Badge>
          )}
        </div>
        <CareLevelDistribution segments={dist} />
      </section>

      <Separator className="mb-6" />

      {/* ───────────── 管理本体（スケジュール / 利用者 / 担当 / ルート） ───────────── */}
      <ManageClient />
    </Container>
  );
}

"use client";

import { DistributionBar } from "@gunjo/ui";

export interface CareLevelDistributionProps {
  segments: { label: string; value: number }[];
}

/**
 * DistributionBar の `formatValue` は関数 prop のため、サーバーコンポーネントから
 * 直接渡すと RSC 境界で "Functions cannot be passed to Client Components" になる。
 * クライアント境界に閉じ込めるための薄いラッパー。
 */
export function CareLevelDistribution({ segments }: CareLevelDistributionProps) {
  return (
    <DistributionBar
      segments={segments}
      showLegend
      totalLabel="人数"
      formatValue={(n) => `${n}名`}
    />
  );
}

"use client";

import * as React from "react";
import {
  Tabs,
  TabsList,
  TabsTrigger,
  TabsContent,
  MetadataList,
  CheckList,
  Badge,
  Tag,
  PersonCell,
  RouteStops,
  SignedRecord,
  CoSign,
  Separator,
  EmptyState,
  type SignedRecordValue,
  type CoSignValue,
} from "@gunjo/ui";
import {
  type Client,
  type Visit,
  carePlans,
  careRecordSeeds,
  getHelper,
  getHelperRoute,
  careLevelLabel,
  visitTypeTone,
  visitStatusBadge,
  supervisorId,
} from "./data";

interface ClientDetailProps {
  client: Client;
  /** 本日その利用者に紐づく訪問のうち、記録対象（完了/実施中）の1件 */
  recordVisit?: Visit;
}

export function ClientDetail({ client, recordVisit }: ClientDetailProps) {
  const helper = getHelper(client.primaryHelperId);
  const plan = carePlans[client.id] ?? [];
  const route = getHelperRoute(client.primaryHelperId);
  const seed = recordVisit ? careRecordSeeds[recordVisit.id] : undefined;

  // 介護記録：下書き→署名（確定）。確定後は2人確認(CoSign)を要求するワークフロー。
  const [record, setRecord] = React.useState<SignedRecordValue>({
    status: "draft",
    addenda: [],
  });
  const [coSign, setCoSign] = React.useState<CoSignValue | undefined>(undefined);

  return (
    <Tabs defaultValue="careplan" className="border-0">
      <TabsList className="w-full">
        <TabsTrigger value="careplan">ケアプラン</TabsTrigger>
        <TabsTrigger value="record">介護記録</TabsTrigger>
        <TabsTrigger value="history">訪問履歴</TabsTrigger>
        <TabsTrigger value="profile">基本情報</TabsTrigger>
      </TabsList>

      {/* ───────────── ケアプラン（週間サービス計画・目標・サービスコード） ───────────── */}
      <TabsContent value="careplan" className="space-y-4 px-0">
        <div className="flex items-center gap-2">
          <h3 className="text-sm font-semibold text-foreground">週間サービス計画</h3>
          <Badge variant="outline">{careLevelLabel(client.careLevel)}</Badge>
          <Badge variant="secondary">週{client.weeklyVisits}回</Badge>
        </div>
        {plan.length > 0 ? (
          <ul className="space-y-3">
            {plan.map((p) => (
              <li key={p.id} className="rounded-lg border border-border bg-card p-3">
                <div className="mb-1.5 flex flex-wrap items-center gap-2">
                  <span className="text-sm font-medium tabular-nums text-foreground">
                    {p.day}・{p.time}
                  </span>
                  <Badge variant={visitTypeTone[p.type]}>{p.type}</Badge>
                  <Tag variant="outline" size="sm">
                    {p.serviceCode}
                  </Tag>
                </div>
                <p className="text-sm text-muted-foreground">
                  <span className="font-medium text-foreground">目標：</span>
                  {p.goal}
                </p>
              </li>
            ))}
          </ul>
        ) : (
          <EmptyState
            title="ケアプラン未登録"
            description="この利用者の週間サービス計画はまだ登録されていません。"
            headingLevel={3}
          />
        )}
      </TabsContent>

      {/* ───────────── 介護記録（バイタル・提供サービス・特記・署名・2人確認） ───────────── */}
      <TabsContent value="record" className="space-y-4 px-0">
        {recordVisit && seed ? (
          <>
            <div className="flex flex-wrap items-center gap-2">
              <h3 className="text-sm font-semibold text-foreground">訪問介護記録</h3>
              <Badge variant={visitStatusBadge[recordVisit.status].variant}>
                {visitStatusBadge[recordVisit.status].label}
              </Badge>
              <span className="text-xs tabular-nums text-muted-foreground">
                {recordVisit.start}〜{recordVisit.end}・{recordVisit.serviceCode}
              </span>
            </div>

            <SignedRecord
              value={record}
              onChange={setRecord}
              signerId={helper.name}
              labels={{
                draft: "下書き",
                signed: "署名・確定済",
                sign: "記録を署名・確定",
                addendaTitle: "追記（修正履歴）",
                addendum: "追記する",
              }}
            >
              {({ readOnly }) => (
                <div className="space-y-4">
                  <section>
                    <p className="mb-1.5 text-xs font-semibold uppercase tracking-wide text-muted-foreground">
                      バイタル
                    </p>
                    <MetadataList
                      layout="horizontal"
                      items={[
                        { label: "体温", value: seed.vitals.temp },
                        { label: "血圧", value: seed.vitals.bp },
                        { label: "脈拍", value: seed.vitals.pulse },
                      ]}
                    />
                  </section>

                  <section>
                    <p className="mb-1.5 text-xs font-semibold uppercase tracking-wide text-muted-foreground">
                      提供したサービス
                    </p>
                    <CheckList
                      items={seed.servicesProvided.map((s, i) => ({
                        id: `svc-${i}`,
                        label: s,
                        checked: true,
                        disabled: readOnly,
                      }))}
                    />
                  </section>

                  <section>
                    <p className="mb-1.5 text-xs font-semibold uppercase tracking-wide text-muted-foreground">
                      特記事項
                    </p>
                    <p className="rounded-md border border-border bg-muted/40 p-3 text-sm leading-relaxed text-foreground">
                      {seed.note}
                    </p>
                  </section>
                </div>
              )}
            </SignedRecord>

            {/* 署名・確定したら、サ責による2人確認（ダブルチェック）を求める */}
            {record.status === "signed" && (
              <>
                <Separator />
                <div className="space-y-2">
                  <p className="text-sm font-medium text-foreground">
                    サービス提供責任者による確認（2人確認）
                  </p>
                  <CoSign
                    primaryId={helper.name}
                    value={coSign}
                    onSign={setCoSign}
                    requireReason={false}
                    signerLabel="確認者（サ責）ID"
                    attestations={[
                      { id: "a1", label: "計画通りのサービスが提供されたことを確認した" },
                      { id: "a2", label: "バイタル・特記事項に異常がないことを確認した" },
                    ]}
                    labels={{ sign: "サ責として確認する", signed: "サ責確認 済" }}
                  />
                </div>
              </>
            )}
          </>
        ) : (
          <EmptyState
            title="本日の記録対象がありません"
            description="完了または実施中の訪問が発生すると、ここに介護記録が表示されます。"
            headingLevel={3}
          />
        )}
      </TabsContent>

      {/* ───────────── 訪問履歴（主担当ヘルパーの本日ルート） ───────────── */}
      <TabsContent value="history" className="space-y-4 px-0">
        <h3 className="text-sm font-semibold text-foreground">
          本日の訪問（主担当：{helper.name}）
        </h3>
        <RouteStops
          stops={route.map((s) => ({
            id: s.visitId,
            title: s.clientName,
            description: `${s.area}・${s.type}`,
            status:
              s.status === "完了"
                ? "completed"
                : s.status === "実施中"
                  ? "current"
                  : s.status === "未実施"
                    ? "failed"
                    : "pending",
            plannedTime: s.plannedStart,
            actualTime: s.actualStart,
          }))}
          statusLabels={{
            completed: "完了",
            current: "実施中",
            failed: "未実施",
            pending: "予定",
          }}
          timeLabels={{ planned: "予定", actual: "実績" }}
        />
      </TabsContent>

      {/* ───────────── 基本情報・担当・緊急連絡先 ───────────── */}
      <TabsContent value="profile" className="space-y-4 px-0">
        <section className="space-y-2">
          <p className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
            担当ヘルパー（主担当）
          </p>
          <div className="rounded-lg border border-border bg-card p-3">
            <PersonCell
              name={helper.name}
              secondary={helper.qualification}
              tertiary={`${helper.employment}・${helper.kana}`}
              presence={helper.presence}
              presenceLabel={helper.duty}
              trailing={<Badge variant="outline">主担当</Badge>}
            />
          </div>
        </section>

        <section className="space-y-2">
          <p className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
            基本情報
          </p>
          <MetadataList
            items={[
              { label: "年齢・性別", value: `${client.age}歳・${client.sex}` },
              { label: "要介護度", value: careLevelLabel(client.careLevel) },
              { label: "週間サービス回数", value: `週${client.weeklyVisits}回` },
              { label: "担当エリア", value: client.area },
              { label: "ケアマネジャー", value: client.caremanager },
            ]}
          />
        </section>

        <section className="space-y-2">
          <p className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
            緊急連絡先・家族
          </p>
          <MetadataList
            items={[
              {
                label: client.emergency.relation,
                value: client.emergency.name,
                description: client.emergency.tel,
              },
            ]}
          />
        </section>
      </TabsContent>
    </Tabs>
  );
}

