export type VisitType = "身体介護" | "生活援助" | "通院介助" | "身体・生活";
export type VisitStatus = "予定" | "実施中" | "完了" | "未実施";

export type CareLevel = 1 | 2 | 3 | 4 | 5;

export interface Helper {
  id: string;
  name: string;
  kana: string;
  /** 資格 */
  qualification: string;
  /** 雇用形態 */
  employment: "常勤" | "登録";
  presence: "online" | "away" | "busy" | "offline";
  /** 本日の稼働状況 */
  duty: "稼働中" | "待機" | "休み";
}

export interface Client {
  id: string;
  name: string;
  kana: string;
  age: number;
  sex: "男" | "女";
  careLevel: CareLevel;
  /** 週間サービス回数 */
  weeklyVisits: number;
  /** 担当ヘルパーID（主担当） */
  primaryHelperId: string;
  /** 住所（エリア） */
  area: string;
  /** 緊急連絡先 */
  emergency: { name: string; relation: string; tel: string };
  /** ケアマネジャー */
  caremanager: string;
}

export interface Visit {
  id: string;
  clientId: string;
  helperId: string;
  /** "HH:MM" 開始 */
  start: string;
  /** "HH:MM" 終了 */
  end: string;
  type: VisitType;
  /** サービスコード（訪問介護） */
  serviceCode: string;
  status: VisitStatus;
  /** 実績開始（HH:MM） */
  actualStart?: string;
  /** 実績終了（HH:MM） */
  actualEnd?: string;
  /** 未実施の理由 */
  absenceReason?: string;
  /** 移動の都合などで競合フラグ */
  conflict?: boolean;
}

