export interface HelperRouteStop {
  visitId: string;
  clientName: string;
  area: string;
  type: VisitType;
  status: VisitStatus;
  plannedStart: string;
  actualStart?: string;
}

export function getHelperRoute(helperId: string): HelperRouteStop[] {
  return visits
    .filter((v) => v.helperId === helperId)
    .sort((a, b) => a.start.localeCompare(b.start))
    .map((v) => {
      const client = clients.find((c) => c.id === v.clientId)!;
      return {
        visitId: v.id,
        clientName: client.name,
        area: client.area,
        type: v.type,
        status: v.status,
        plannedStart: v.start,
        actualStart: v.actualStart,
      };
    });
}

