const SCHEDULE_TONE: Record<VisitStatus, ScheduleCell["tone"]> = {
  予定: "muted",
  実施中: "info",
  完了: "success",
  未実施: "destructive",
};

/** 利用者ごとの本日の代表ステータス（実施中>未実施>予定>完了 の優先で1つ） */
function todayStatusFor(clientId: string): VisitStatus | null {
  const todays = visits.filter((v) => v.clientId === clientId);
  if (todays.length === 0) return null;
  const order: VisitStatus[] = ["実施中", "未実施", "予定", "完了"];
  for (const s of order) if (todays.some((v) => v.status === s)) return s;
  return "完了";
}

/**
 * 記録対象の訪問を1件返す。実施中→完了の順で、かつ記録の下地(seed)がある訪問を優先。
 * 詳細パネルは利用者単位のため、クリックしたセルと別の訪問が出ることがある。
 */
function recordVisitFor(clientId: string): Visit | undefined {
  const todays = visits.filter(
    (v) => v.clientId === clientId && (v.status === "完了" || v.status === "実施中"),
  );
  const seeded = todays.filter((v) => careRecordSeeds[v.id]);
  const pool = seeded.length > 0 ? seeded : todays;
  return pool.find((v) => v.status === "実施中") ?? pool[0];
}

